python3 -c "
import json, sys
from pathlib import Path

run_dir = Path('rllm_train/output/runs/run_1780283875')
jsonl = run_dir / 'verl_metrics.jsonl'

steps = []
for line in jsonl.read_text().strip().split('\n'):
    if not line.strip(): continue
    try: steps.append(json.loads(line))
    except: pass

last = steps[-1]; data = last['data']; s = last['step']; n = len(steps)
print(f'=== Step {s} ({n} total) ===')
metrics = [
    ('Reward', 'critic/score/mean', '.4f'), ('R_max', 'critic/score/max', '.4f'),
    ('R_min', 'critic/score/min', '.4f'), ('Advantage', 'critic/advantages/mean', '.4f'),
    ('pg_loss', 'actor/pg_loss', '+.4f'), ('grad_norm', 'actor/grad_norm', '.4f'),
    ('entropy', 'actor/entropy', '.4f'), ('clipfrac', 'actor/pg_clipfrac', '.4f'),
    ('ppo_kl', 'actor/ppo_kl', '.4f'), ('lr', 'actor/lr', '.2e'),
    ('resp_len', 'response_length/mean', '.0f'), ('resp_clip', 'response_length/clip_ratio', '.3f'),
    ('abort', 'response/aborted_ratio', '.3f'), ('turns', 'num_turns/mean', '.1f'),
    ('t_step', 'timing_s/step', '.1f'), ('throughput', 'perf/throughput', '.0f'),
    ('epoch', 'training/epoch', '.2f'),
]
for label, key, fmt in metrics:
    v = data.get(key)
    if v is not None: print(f'  {label:12s} = {v:{fmt}}')

# 8-dim
scores = [s['data'].get('critic/score/mean', 0) for s in steps]
score_maxs = [s['data'].get('critic/score/max', 0) for s in steps]
score_mins = [s['data'].get('critic/score/min', 0) for s in steps]
grads = [s['data'].get('actor/grad_norm', 0) for s in steps]
ents = [s['data'].get('actor/entropy', 0) for s in steps]
advs = [s['data'].get('critic/advantages/mean', 0) for s in steps]
aborts = [s['data'].get('response/aborted_ratio', 0) for s in steps]
w = min(5, n)

alerts = []
if n >= 5 and all(g < 0.01 for g in grads[-w:]): alerts.append(('S0', 'lr_half', f'grad_norm<0.01'))
if n >= 3 and all(e < 0.01 for e in ents[-3:]): alerts.append(('S1', 'entropy_bonus', f'entropy<0.01'))
if n >= 2 and all(e > 2.0 for e in ents[-2:]): alerts.append(('S2', 'entropy_bonus', f'entropy>2.0'))
if n >= 3 and all(scores[i]==0 and score_maxs[i]==0 for i in range(n-3,n)): alerts.append(('S3', 'diagnose', f'zero reward'))
if n >= 5 and all(abs(advs[i])<0.001 and score_maxs[i]>0.5 for i in range(n-5,n)): alerts.append(('S4', None, f'plateau'))
if n >= 3 and all(a>0.5 for a in aborts[-3:]): alerts.append(('S5', 'diagnose', f'abort spike'))
if any(g>100 for g in grads[-w:]): alerts.append(('S6', 'lr_tenth', f'grad>100'))
if n >= 5 and all(abs(score_maxs[i]-score_mins[i])<0.001 for i in range(n-5,n)): alerts.append(('S7', None, f'var zero'))

print(f'\nDiagnosis ({n} steps): reward avg={sum(scores)/n:.4f} max={max(scores):.4f} | grad avg={sum(grads)/n:.4f} | ent {ents[0]:.3f}->{ents[-1]:.3f} | abort avg={sum(aborts)/n:.3f}')
statuses = [f'S{i}:{\"ALERT\" if any(a[0]==f\"S{i}\" for a in alerts) else \"ok\"}' for i in range(8)]
print(f'  {\" | \".join(statuses)}')

CRITICAL = {'S0','S1','S2','S3','S5','S6'}
critical_hits = [a for a in alerts if a[0] in CRITICAL]
warn_hits = [a for a in alerts if a[0] in {'S4','S7'}]
if critical_hits:
    hit = critical_hits[0]
    print(f'=== CIRCUIT_BREAK ===\ncircuit_break: true\nabort_reason: {hit[0]}: {hit[2]}\nfix_preset: {hit[1]}\nanalysis_json: {run_dir}/analysis.json\n=== END_CIRCUIT_BREAK ===')
elif warn_hits:
    for w_hit in warn_hits: print(f'WARN: {w_hit[0]}: {w_hit[2]}')
"
